// gribtract-fetch: HTTP byte-range fetching for NOAA GRIB2 data
//
// This crate provides HTTP byte-range fetching capabilities for retrieving GRIB2
// data from NOAA's public data sources:
// - NOAA S3 buckets: noaa-hrrr-bdp-pds, noaa-gefs-pds, noaa-nbm-grib2-pds
// - Google Cloud Storage: high-resolution-rapid-refresh, national-blend-of-models, gfs-ensemble-forecast-system
// - NOMADS: nomads.ncep.noaa.gov
//
// # Feature flags
// - `async`: Enable async HTTP client with tokio support
// - `probe`: Enable provider probing and selection

#![cfg_attr(docsrs, feature(doc_auto_cfg))]

pub mod client;
pub mod error;
pub mod provider;

pub use client::{FetchClient, RangeRequest};
pub use error::{FetchError, Result};
pub use provider::{DataProvider, NomadsProvider, S3Provider, StorageProvider};

#[cfg(feature = "probe")]
pub mod probe;

#[cfg(feature = "probe")]
pub use probe::{ProbeResult, ProviderProbe};

/// Re-export reqwest::StatusCode for convenience
pub use reqwest::StatusCode;

//! Error types for gribtract-fetch

use std::fmt;

/// Result type for fetch operations
pub type Result<T> = std::result::Result<T, FetchError>;

/// Errors that can occur during HTTP fetch operations
#[derive(Debug, thiserror::Error)]
pub enum FetchError {
    /// HTTP request failed
    #[error("HTTP request failed: {0}")]
    HttpError(#[from] reqwest::Error),

    /// Invalid HTTP status code
    #[error("HTTP error: {0}")]
    HttpStatus(StatusCode),

    /// Invalid range request format
    #[error("Invalid range request: {0}")]
    InvalidRange(String),

    /// Content range header missing or invalid
    #[error("Invalid content-range header: {0}")]
    InvalidContentRange(String),

    /// URL parsing error
    #[error("Invalid URL: {0}")]
    InvalidUrl(String),

    /// IO error
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),

    /// Provider probe error
    #[cfg(feature = "probe")]
    #[error("Provider probe failed: {0}")]
    ProbeError(String),

    /// Timeout
    #[error("Operation timed out after {0:?}")]
    Timeout(std::time::Duration),
}

/// Re-export StatusCode for convenience
pub use reqwest::StatusCode;

impl FetchError {
    /// Check if this error is retryable (e.g., network errors, 5xx status codes)
    pub fn is_retryable(&self) -> bool {
        match self {
            FetchError::HttpError(e) => {
                // Consider network errors as retryable
                e.is_timeout() || e.is_connect() || e.is_body() || e.is_request()
            }
            FetchError::HttpStatus(code) => {
                // Retry on 5xx server errors and 429 (too many requests)
                code.is_server_error() || *code == StatusCode::TOO_MANY_REQUESTS
            }
            _ => false,
        }
    }
}

//! Data provider abstractions for NOAA GRIB2 sources

use crate::{error::Result, FetchError};
use std::fmt;

/// Base URL for NOAA S3 buckets (public access, no auth required)
const NOAA_S3_BASE: &str = "https://noaa-";

/// Base URL for Google Cloud Storage buckets (public access)
const GCS_BASE: &str = "https://storage.googleapis.com/";

/// Base URL for NOMADS (NOAA's data server)
const NOMADS_BASE: &str = "https://nomads.ncep.noaa.gov/";

/// Supported GRIB2 data providers
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DataProvider {
    /// NOAA S3 buckets (us-east-1 region)
    S3(S3Bucket),
    /// Google Cloud Storage (CDN-fronted)
    Gcs(GcsBucket),
    /// NOMADS HTTP server
    Nomads(NomadsModel),
}

impl fmt::Display for DataProvider {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            DataProvider::S3(bucket) => write!(f, "S3:{}", bucket),
            DataProvider::Gcs(bucket) => write!(f, "GCS:{}", bucket),
            DataProvider::Nomads(model) => write!(f, "NOMADS:{}", model),
        }
    }
}

/// NOAA S3 buckets available for public access
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum S3Bucket {
    /// HRRR (High-Resolution Rapid Refresh) model data
    HrrrBdp,
    /// GEFS (Global Ensemble Forecast System) model data
    GefsPds,
    /// NBM (National Blend of Models) GRIB2 data
    NbmGrib2,
    /// GFS (Global Forecast System) model data
    GfsPds,
}

impl fmt::Display for S3Bucket {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            S3Bucket::HrrrBdp => write!(f, "noaa-hrrr-bdp-pds"),
            S3Bucket::GefsPds => write!(f, "noaa-gefs-pds"),
            S3Bucket::NbmGrib2 => write!(f, "noaa-nbm-grib2-pds"),
            S3Bucket::GfsPds => write!(f, "noaa-gfs-bdp-pds"),
        }
    }
}

impl S3Bucket {
    /// Get the full S3 bucket URL
    pub fn base_url(&self) -> String {
        format!("{}{s}.s3.amazonaws.com/", NOAA_S3_BASE, s = self)
    }

    /// Convert from string (for config parsing)
    pub fn from_str(s: &str) -> Result<Self> {
        match s.to_lowercase().as_str() {
            "noaa-hrrr-bdp-pds" | "hrrr" => Ok(S3Bucket::HrrrBdp),
            "noaa-gefs-pds" | "gefs" => Ok(S3Bucket::GefsPds),
            "noaa-nbm-grib2-pds" | "nbm" => Ok(S3Bucket::NbmGrib2),
            "noaa-gfs-bdp-pds" | "gfs" => Ok(S3Bucket::GfsPds),
            _ => Err(FetchError::InvalidUrl(format!("Unknown S3 bucket: {}", s))),
        }
    }
}

/// Google Cloud Storage buckets mirroring NOAA data
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum GcsBucket {
    /// HRRR model data on GCS
    HighResolutionRapidRefresh,
    /// NBM model data on GCS
    NationalBlendOfModels,
    /// GEFS model data on GCS
    GfsEnsembleForecastSystem,
}

impl fmt::Display for GcsBucket {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            GcsBucket::HighResolutionRapidRefresh => write!(f, "high-resolution-rapid-refresh"),
            GcsBucket::NationalBlendOfModels => write!(f, "national-blend-of-models"),
            GcsBucket::GfsEnsembleForecastSystem => write!(f, "gfs-ensemble-forecast-system"),
        }
    }
}

impl GcsBucket {
    /// Get the full GCS bucket URL
    pub fn base_url(&self) -> String {
        format!("{}{b}/", GCS_BASE, b = self)
    }

    /// Convert from string
    pub fn from_str(s: &str) -> Result<Self> {
        match s.to_lowercase().as_str() {
            "high-resolution-rapid-refresh" | "hrrr" => Ok(GcsBucket::HighResolutionRapidRefresh),
            "national-blend-of-models" | "nbm" => Ok(GcsBucket::NationalBlendOfModels),
            "gfs-ensemble-forecast-system" | "gefs" => Ok(GcsBucket::GfsEnsembleForecastSystem),
            _ => Err(FetchError::InvalidUrl(format!("Unknown GCS bucket: {}", s))),
        }
    }
}

/// NOMADS model endpoints
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum NomadsModel {
    /// GFS model via NOMADS
    Gfs,
    /// GEFS model via NOMADS
    Gefs,
    /// NAM model via NOMADS
    Nam,
}

impl fmt::Display for NomadsModel {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            NomadsModel::Gfs => write!(f, "gfs"),
            NomadsModel::Gefs => write!(f, "gefs"),
            NomadsModel::Nam => write!(f, "nam"),
        }
    }
}

impl NomadsModel {
    /// Get the base NOMADS URL for this model
    pub fn base_url(&self) -> String {
        format!("{}{m}/", NOMADS_BASE, m = self)
    }

    /// Convert from string
    pub fn from_str(s: &str) -> Result<Self> {
        match s.to_lowercase().as_str() {
            "gfs" => Ok(NomadsModel::Gfs),
            "gefs" => Ok(NomadsModel::Gefs),
            "nam" => Ok(NomadsModel::Nam),
            _ => Err(FetchError::InvalidUrl(format!("Unknown NOMADS model: {}", s))),
        }
    }
}

impl DataProvider {
    /// Get the base URL for this provider
    pub fn base_url(&self) -> String {
        match self {
            DataProvider::S3(bucket) => bucket.base_url(),
            DataProvider::Gcs(bucket) => bucket.base_url(),
            DataProvider::Nomads(model) => model.base_url(),
        }
    }

    /// Create a provider from a string identifier
    pub fn from_string(s: &str) -> Result<Self> {
        let parts: Vec<&str> = s.split(':').collect();
        if parts.len() != 2 {
            return Err(FetchError::InvalidUrl(
                "Provider must be in format 'type:name' (e.g., 's3:hrrr')".into(),
            ));
        }

        match parts[0].to_lowercase().as_str() {
            "s3" => Ok(DataProvider::S3(S3Bucket::from_str(parts[1])?)),
            "gcs" => Ok(DataProvider::Gcs(GcsBucket::from_str(parts[1])?)),
            "nomads" => Ok(DataProvider::Nomads(NomadsModel::from_str(parts[1])?)),
            _ => Err(FetchError::InvalidUrl(format!("Unknown provider type: {}", parts[0]))),
        }
    }
}

/// Storage provider trait for common operations
pub trait StorageProvider {
    /// Get the base URL for this provider
    fn base_url(&self) -> String;

    /// Check if this provider supports HTTP range requests
    fn supports_range_requests(&self) -> bool {
        true
    }
}

impl StorageProvider for S3Bucket {
    fn base_url(&self) -> String {
        Self::base_url(self)
    }
}

impl StorageProvider for GcsBucket {
    fn base_url(&self) -> String {
        Self::base_url(self)
    }
}

impl StorageProvider for NomadsModel {
    fn base_url(&self) -> String {
        Self::base_url(self)
    }
}

//! HTTP client for byte-range fetching

use crate::error::{FetchError, Result};
use crate::provider::{DataProvider, StorageProvider};
use bytes::Bytes;
use std::ops::Range;
use std::time::Duration;

/// HTTP range request specification
#[derive(Debug, Clone)]
pub struct RangeRequest {
    /// Start byte position (inclusive)
    pub start: u64,
    /// End byte position (inclusive), or None for fetch to end
    pub end: Option<u64>,
}

impl RangeRequest {
    /// Create a new range request
    pub fn new(start: u64, end: Option<u64>) -> Self {
        Self { start, end }
    }

    /// Create a range request with a specified length
    pub fn with_length(start: u64, length: u64) -> Self {
        Self {
            start,
            end: Some(start + length - 1),
        }
    }

    /// Create a range request from a Rust Range (end is exclusive)
    pub fn from_range(range: Range<u64>) -> Self {
        Self {
            start: range.start,
            end: if range.end > 0 {
                Some(range.end - 1)
            } else {
                None
            },
        }
    }

    /// Get the Range header value for HTTP requests
    pub fn to_header_value(&self) -> String {
        match self.end {
            Some(end) => format!("bytes={}-{}", self.start, end),
            None => format!("bytes={}-", self.start),
        }
    }

    /// Get the total number of bytes requested
    pub fn length(&self) -> Option<u64> {
        self.end.map(|end| end - self.start + 1)
    }
}

/// Response from a range request
#[derive(Debug)]
pub struct RangeResponse {
    /// The requested bytes
    pub data: Bytes,
    /// The actual content range returned by the server
    pub content_range: ContentRange,
    /// Total size of the resource (if known)
    pub total_size: Option<u64>,
}

/// Content-Range header information
#[derive(Debug, Clone)]
pub struct ContentRange {
    /// Start byte position
    pub start: u64,
    /// End byte position (inclusive)
    pub end: u64,
    /// Total resource size (or None if unknown/asterisk)
    pub total: Option<u64>,
}

impl ContentRange {
    /// Parse from Content-Range header value
    ///
    /// Format: `bytes start-end/total` or `bytes */total` or `bytes start-end/*`
    pub fn parse(header: &str) -> Result<Self> {
        let header = header.trim();
        if !header.starts_with("bytes ") {
            return Err(FetchError::InvalidContentRange(format!(
                "Missing 'bytes' prefix: {}",
                header
            )));
        }

        let parts: Vec<&str> = header[6..].split('/').collect();
        if parts.len() != 2 {
            return Err(FetchError::InvalidContentRange(format!(
                "Invalid format: {}",
                header
            )));
        }

        let total = match parts[1] {
            "*" => None,
            s => Some(
                s.parse::<u64>()
                    .map_err(|_| FetchError::InvalidContentRange(format!("Invalid total: {}", s)))?,
            ),
        };

        if parts[0] == "*" {
            return Ok(ContentRange {
                start: 0,
                end: 0,
                total,
            });
        }

        let range_parts: Vec<&str> = parts[0].split('-').collect();
        if range_parts.len() != 2 {
            return Err(FetchError::InvalidContentRange(format!(
                "Invalid range format: {}",
                header
            )));
        }

        let start = range_parts[0]
            .parse::<u64>()
            .map_err(|_| FetchError::InvalidContentRange(format!("Invalid start: {}", range_parts[0])))?;
        let end = range_parts[1]
            .parse::<u64>()
            .map_err(|_| FetchError::InvalidContentRange(format!("Invalid end: {}", range_parts[1])))?;

        Ok(ContentRange { start, end, total })
    }

    /// Get the length of this range
    pub fn length(&self) -> u64 {
        self.end - self.start + 1
    }
}

/// HTTP client for fetching GRIB2 data via byte-range requests
#[derive(Debug, Clone)]
pub struct FetchClient {
    client: reqwest::Client,
    default_timeout: Duration,
}

impl FetchClient {
    /// Create a new fetch client with default settings
    pub fn new() -> Self {
        Self::with_timeout(Duration::from_secs(30))
    }

    /// Create a new fetch client with a specified timeout
    pub fn with_timeout(timeout: Duration) -> Self {
        let client = reqwest::Client::builder()
            .timeout(timeout)
            .gzip(true)
            .build()
            .expect("Failed to build HTTP client");

        Self {
            client,
            default_timeout: timeout,
        }
    }

    /// Create a fetch client from an existing reqwest client
    pub fn from_client(client: reqwest::Client) -> Self {
        Self {
            default_timeout: Duration::from_secs(30),
            client,
        }
    }

    /// Fetch a byte range from a URL
    pub async fn fetch_range(&self, url: &str, range: RangeRequest) -> Result<RangeResponse> {
        let header_value = range.to_header_value();

        let response = self
            .client
            .get(url)
            .header("Range", header_value)
            .send()
            .await?;

        let status = response.status();

        if !status.is_success() {
            return Err(FetchError::HttpStatus(status));
        }

        let content_range_header = response
            .headers()
            .get("content-range")
            .and_then(|v| v.to_str().ok());

        let content_range = match content_range_header {
            Some(header) => ContentRange::parse(header)?,
            None => {
                // Some providers might not return Content-Range for 200 OK responses
                // (they return the full resource instead of a range)
                return Err(FetchError::InvalidContentRange(
                    "Missing Content-Range header".into(),
                ));
            }
        };

        let total_size = content_range.total;
        let data = response.bytes().await?;

        Ok(RangeResponse {
            data,
            content_range,
            total_size,
        })
    }

    /// Fetch the first N bytes from a URL
    pub async fn fetch_head(&self, url: &str, length: u64) -> Result<RangeResponse> {
        self.fetch_range(url, RangeRequest::with_length(0, length)).await
    }

    /// Fetch the entire resource (no range request)
    pub async fn fetch_all(&self, url: &str) -> Result<Bytes> {
        let response = self.client.get(url).send().await?;

        let status = response.status();
        if !status.is_success() {
            return Err(FetchError::HttpStatus(status));
        }

        Ok(response.bytes().await?)
    }

    /// Get the resource size with a HEAD request (Content-Length header)
    pub async fn resource_size(&self, url: &str) -> Result<Option<u64>> {
        let response = self.client.head(url).send().await?;
        let status = response.status();

        if !status.is_success() {
            return Err(FetchError::HttpStatus(status));
        }

        Ok(response
            .headers()
            .get("content-length")
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.parse::<u64>().ok()))
    }

    /// Check if the URL is accessible and supports range requests
    pub async fn probe(&self, url: &str) -> Result<ProbeInfo> {
        let start = std::time::Instant::now();

        let response = self
            .client
            .head(url)
            .send()
            .await?;

        let status = response.status();
        if !status.is_success() {
            return Err(FetchError::HttpStatus(status));
        }

        let connect_time = start.elapsed();
        let supports_range = response
            .headers()
            .get("accept-ranges")
            .and_then(|v| v.to_str().ok())
            .map(|v| v.to_lowercase() == "bytes")
            .unwrap_or(false);

        let content_length = response
            .headers()
            .get("content-length")
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.parse::<u64>().ok());

        Ok(ProbeInfo {
            url: url.to_string(),
            connect_time,
            supports_range,
            content_length,
        })
    }
}

impl Default for FetchClient {
    fn default() -> Self {
        Self::new()
    }
}

/// Information about a URL from a probe request
#[derive(Debug, Clone)]
pub struct ProbeInfo {
    /// The URL that was probed
    pub url: String,
    /// Time to establish connection and get HEAD response
    pub connect_time: Duration,
    /// Whether the server supports range requests
    pub supports_range: bool,
    /// Content length if available
    pub content_length: Option<u64>,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_range_request_header() {
        let range = RangeRequest::new(100, Some(199));
        assert_eq!(range.to_header_value(), "bytes=100-199");

        let range = RangeRequest::new(100, None);
        assert_eq!(range.to_header_value(), "bytes=100-");

        let range = RangeRequest::with_length(0, 1024);
        assert_eq!(range.to_header_value(), "bytes=0-1023");

        let range = RangeRequest::from_range(100..200);
        assert_eq!(range.to_header_value(), "bytes=100-199");
    }

    #[test]
    fn test_content_range_parse() {
        let cr = ContentRange::parse("bytes 0-1023/2048").unwrap();
        assert_eq!(cr.start, 0);
        assert_eq!(cr.end, 1023);
        assert_eq!(cr.total, Some(2048));
        assert_eq!(cr.length(), 1024);

        let cr = ContentRange::parse("bytes 0-1023/*").unwrap();
        assert_eq!(cr.start, 0);
        assert_eq!(cr.end, 1023);
        assert_eq!(cr.total, None);

        let cr = ContentRange::parse("bytes */2048").unwrap();
        assert_eq!(cr.start, 0);
        assert_eq!(cr.end, 0);
        assert_eq!(cr.total, Some(2048));
    }

    #[test]
    fn test_provider_urls() {
        use crate::provider::{S3Bucket, GcsBucket, NomadsModel, StorageProvider};

        let hrrr = S3Bucket::HrrrBdp;
        assert_eq!(
            hrrr.base_url(),
            "https://noaa-noaa-hrrr-bdp-pds.s3.amazonaws.com/"
        );

        let hrrr_gcs = GcsBucket::HighResolutionRapidRefresh;
        assert_eq!(
            hrrr_gcs.base_url(),
            "https://storage.googleapis.com/high-resolution-rapid-refresh/"
        );

        let gfs = NomadsModel::Gfs;
        assert_eq!(gfs.base_url(), "https://nomads.ncep.noaa.gov/gfs/");
    }
}

//! Provider probing and selection

use crate::client::FetchClient;
use crate::provider::{DataProvider, S3Bucket, GcsBucket, NomadsModel};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::time::Duration;

/// Result of probing a single provider for a specific model
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProbeResult {
    /// The provider that was probed
    pub provider: String,
    /// URL used for probing (typically a recent .idx file)
    pub probe_url: String,
    /// TCP connect time + TTFB for the probe request
    pub connect_ms: u64,
    /// Time to first byte (TTFB) in milliseconds
    pub ttfb_ms: u64,
    /// Throughput measured during the probe (bytes/sec)
    pub throughput_mbs: f64,
    /// Combined score (lower is better)
    pub score: f64,
    /// Whether the probe was successful
    pub success: bool,
    /// Error message if the probe failed
    pub error: Option<String>,
    /// Timestamp of the probe
    pub timestamp: String,
}

/// Provider probe results for all providers and models
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProviderProbeResults {
    /// Results per model
    pub models: HashMap<String, Vec<ProbeResult>>,
    /// Timestamp when the probe was run
    pub timestamp: String,
    /// Git commit hash for reproducibility
    pub git_sha: Option<String>,
}

/// Provider probe client
///
/// Probes each provider for each model at startup to determine the fastest provider
/// for the current deployment location.
#[derive(Debug)]
pub struct ProviderProbe {
    client: FetchClient,
    /// Test files to use for probing (small .idx files)
    probe_files: HashMap<String, Vec<(String, String)>>,
}

impl ProviderProbe {
    /// Create a new provider probe client
    pub fn new() -> Self {
        Self {
            client: FetchClient::new(),
            probe_files: Self::default_probe_files(),
        }
    }

    /// Create a new provider probe client with a custom HTTP client
    pub fn with_client(client: FetchClient) -> Self {
        Self {
            client,
            probe_files: Self::default_probe_files(),
        }
    }

    /// Get default probe files for each model
    ///
    /// Returns a map of model name to list of (provider, url) tuples
    fn default_probe_files() -> HashMap<String, Vec<(String, String)>> {
        let mut files = HashMap::new();

        // HRRR model probe files
        files.insert(
            "hrrr".to_string(),
            vec![
                ("s3:hrrr-bdp".to_string(), "https://noaa-hrrr-bdp-pds.s3.amazonaws.com/hrrr.20250702/conus/hrrr.t00z.wrfsfcf00.grib2.idx".to_string()),
                ("gcs:hrrr".to_string(), "https://storage.googleapis.com/high-resolution-rapid-refresh/hrrr.20250702/conus/hrrr.t00z.wrfsfcf00.grib2.idx".to_string()),
            ],
        );

        // GEFS model probe files
        files.insert(
            "gefs".to_string(),
            vec![
                ("s3:gefs-pds".to_string(), "https://noaa-gefs-pds.s3.amazonaws.com/gefs.20250702/00/wave/grb2/gefs.wave.t00z.prtcgrb.idx.0p25".to_string()),
                ("gcs:gefs".to_string(), "https://storage.googleapis.com/gfs-ensemble-forecast-system/gefs.20250702/00/wave/grb2/gefs.wave.t00z.prtcgrb.idx.0p25".to_string()),
            ],
        );

        // NBM model probe files
        files.insert(
            "nbm".to_string(),
            vec![
                ("s3:nbm-grib2".to_string(), "https://noaa-nbm-grib2-pds.s3.amazonaws.com/nbm.20250702/nbm.t00z.conusnest.2p5.f000.co.grib2.idx".to_string()),
                ("gcs:nbm".to_string(), "https://storage.googleapis.com/national-blend-of-models/nbm.20250702/nbm.t00z.conusnest.2p5.f000.co.grib2.idx".to_string()),
            ],
        );

        // GFS model probe files
        files.insert(
            "gfs".to_string(),
            vec![
                ("s3:gfs-pds".to_string(), "https://noaa-gfs-bdp-pds.s3.amazonaws.com/gfs.20250702/00/gfs.t00z.pgrb2.0p25.f000.idx".to_string()),
                ("nomads:gfs".to_string(), "https://nomads.ncep.noaa.gov/pub/data/nccf/com/gfs/prod/gfs.20250702/00/atmos/gfs.t00z.pgrb2.0p25.f000.idx".to_string()),
            ],
        );

        files
    }

    /// Probe all providers for all models
    pub async fn probe_all(&self) -> ProviderProbeResults {
        let mut results = HashMap::new();
        let timestamp = chrono::Utc::now().to_rfc3339();

        for (model, probe_files) in &self.probe_files {
            let mut model_results = Vec::new();

            for (provider, url) in probe_files {
                let result = self.probe_url(provider, url).await;
                model_results.push(result);
            }

            // Sort by score (lower is better)
            model_results.sort_by(|a, b| {
                a.score.partial_cmp(&b.score).unwrap_or(std::cmp::Ordering::Equal)
            });

            results.insert(model.clone(), model_results);
        }

        ProviderProbeResults {
            models: results,
            timestamp,
            git_sha: Self::get_git_sha(),
        }
    }

    /// Probe a single URL
    async fn probe_url(&self, provider: &str, url: &str) -> ProbeResult {
        let start = std::time::Instant::now();

        match self.probe_url_inner(url).await {
            Ok(result) => {
                let elapsed = start.elapsed();
                ProbeResult {
                    provider: provider.to_string(),
                    probe_url: url.to_string(),
                    connect_ms: result.connect_time.as_millis() as u64,
                    ttfb_ms: result.ttfb.as_millis() as u64,
                    throughput_mbs: result.throughput_mbs,
                    score: Self::calculate_score(&result),
                    success: true,
                    error: None,
                    timestamp: chrono::Utc::now().to_rfc3339(),
                }
            }
            Err(e) => {
                let elapsed = start.elapsed();
                ProbeResult {
                    provider: provider.to_string(),
                    probe_url: url.to_string(),
                    connect_ms: elapsed.as_millis() as u64,
                    ttfb_ms: elapsed.as_millis() as u64,
                    throughput_mbs: 0.0,
                    score: f64::MAX,
                    success: false,
                    error: Some(e.to_string()),
                    timestamp: chrono::Utc::now().to_rfc3339(),
                }
            }
        }
    }

    /// Inner probe logic for a single URL
    async fn probe_url_inner(&self, url: &str) -> Result<ProbeInnerResult, crate::FetchError> {
        let start = std::time::Instant::now();

        // First, do a HEAD request to measure connect time and check range support
        let head_response = self.client.client.head(url).send().await?;
        let connect_time = start.elapsed();

        let status = head_response.status();
        if !status.is_success() {
            return Err(crate::FetchError::HttpStatus(status));
        }

        // Check if range requests are supported
        let supports_range = head_response
            .headers()
            .get("accept-ranges")
            .and_then(|v| v.to_str().ok())
            .map(|v| v.to_lowercase() == "bytes")
            .unwrap_or(false);

        // Get content length
        let content_length = head_response
            .headers()
            .get("content-length")
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.parse::<u64>().ok())
            .unwrap_or(0);

        // Now do a small range request to measure TTFB and throughput
        let range_start = std::time::Instant::now();

        let range_response = if supports_range && content_length > 1024 {
            Some(self.client.fetch_head(url, 1024).await?)
        } else {
            None
        };

        let ttfb = range_start.elapsed();

        let throughput_mbs = if let Some(resp) = range_response {
            let bytes = resp.data.len() as f64;
            let seconds = ttfb.as_secs_f64();
            (bytes / seconds) / (1024.0 * 1024.0)
        } else {
            0.0
        };

        Ok(ProbeInnerResult {
            connect_time,
            ttfb,
            throughput_mbs,
        })
    }

    /// Calculate a combined score for provider selection
    ///
    /// Lower is better. Formula: connect_ms + ttfb_ms + (1 / throughput_mbs)
    fn calculate_score(result: &ProbeInnerResult) -> f64 {
        let connect_penalty = result.connect_time.as_millis() as f64;
        let ttfb_penalty = result.ttfb.as_millis() as f64;
        let throughput_penalty = if result.throughput_mbs > 0.0 {
            1000.0 / result.throughput_mbs
        } else {
            10000.0 // Large penalty for no throughput
        };

        connect_penalty + ttfb_penalty + throughput_penalty
    }

    /// Get the current git SHA for reproducibility
    fn get_git_sha() -> Option<String> {
        std::process::Command::new("git")
            .args(["rev-parse", "HEAD"])
            .output()
            .ok()
            .and_then(|output| {
                let sha = String::from_utf8_lossy(&output.stdout).trim().to_string();
                if !sha.is_empty() {
                    Some(sha)
                } else {
                    None
                }
            })
    }

    /// Get the best provider for a model based on probe results
    pub fn get_best_provider(
        results: &ProviderProbeResults,
        model: &str,
    ) -> Option<&ProbeResult> {
        results.models.get(model).and_then(|model_results| {
            model_results.iter().find(|r| r.success)
        })
    }

    /// Write probe results to a JSON file
    pub fn write_results(results: &ProviderProbeResults, path: &std::path::Path) -> std::io::Result<()> {
        let json = serde_json::to_string_pretty(results)?;
        std::fs::write(path, json)
    }

    /// Load probe results from a JSON file
    pub fn load_results(path: &std::path::Path) -> std::io::Result<ProviderProbeResults> {
        let json = std::fs::read_to_string(path)?;
        let results: ProviderProbeResults = serde_json::from_str(&json)?;
        Ok(results)
    }

    /// Check if probe results are stale (older than 24 hours)
    pub fn is_stale(results: &ProviderProbeResults, max_age: Duration) -> bool {
        match chrono::DateTime::parse_from_rfc3339(&results.timestamp) {
            Ok(timestamp) => {
                let now = chrono::Utc::now();
                let age = now.signed_duration_since(timestamp);
                age.to_std().unwrap_or(Duration::ZERO) > max_age
            }
            Err(_) => true, // Invalid timestamp means stale
        }
    }
}

impl Default for ProviderProbe {
    fn default() -> Self {
        Self::new()
    }
}

/// Inner result from a single probe
#[derive(Debug)]
struct ProbeInnerResult {
    connect_time: Duration,
    ttfb: Duration,
    throughput_mbs: f64,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[tokio::test]
    #[ignore] // Requires network access
    async fn test_probe_hrrr() {
        let probe = ProviderProbe::new();
        let results = probe.probe_all().await;

        println!("Probe results: {}", serde_json::to_string_pretty(&results).unwrap());

        // Check that we got results for HRRR
        assert!(results.models.contains_key("hrrr"));

        let hrrr_results = &results.models["hrrr"];
        assert!(!hrrr_results.is_empty());

        // At least one provider should succeed
        let successful = hrrr_results.iter().filter(|r| r.success).count();
        assert!(successful > 0, "At least one HRRR provider should succeed");
    }

    #[test]
    fn test_score_calculation() {
        let result = ProbeInnerResult {
            connect_time: Duration::from_millis(50),
            ttfb: Duration::from_millis(100),
            throughput_mbs: 10.0,
        };

        let score = ProviderProbe::calculate_score(&result);
        // connect_penalty = 50, ttfb_penalty = 100, throughput_penalty = 1000/10 = 100
        // total = 250
        assert!((score - 250.0).abs() < 1.0);
    }
}

